// Calculate nutrition insights and generate report
const userData = $input.all();
const reports = [];

for (const user of userData) {
  const data = user.json;
  const insights = [];
  const caloriePercentage = (data.total_calories / data.daily_calorie_target) * 100;
  const proteinPercentage = (data.total_protein / data.daily_protein_target) * 100;

  // Generate insights based on performance
  if (caloriePercentage < 80) {
    insights.push("You're under your calorie goal. Consider adding healthy snacks!");
  } else if (caloriePercentage > 120) {
    insights.push("You exceeded your calorie goal. Focus on portion control tomorrow.");
  } else {
    insights.push("Great job hitting your calorie target! 🎉");
  }

  if (proteinPercentage < 80) {
    insights.push("Increase your protein intake with lean meats or plant-based proteins.");
  }

  const report = {
    user_id: data.id,
    email: data.email,
    name: data.name,
    date: new Date().toLocaleDateString(),
    calories: {
      consumed: data.total_calories,
      target: data.daily_calorie_target,
      percentage: Math.round(caloriePercentage)
    },
    protein: {
      consumed: data.total_protein,
      target: data.daily_protein_target,
      percentage: Math.round(proteinPercentage)
    },
    insights: insights,
    emoji: caloriePercentage >= 80 && caloriePercentage <= 120 ? '🎉' : caloriePercentage < 80 ? '📈' : '⚠️'
  };

  reports.push(report);
}

return reports.map(report => ({ json: report }));

// Process AI response and prepare email content
const nutritionData = $input.all();
const emailContents = [];

for (const item of nutritionData) {
  const data = item.json;
  const aiSummary = JSON.parse(data.message.content);

  const emailContent = {
    user_id: data.user_id,
    email: data.email,
    name: data.name,
    date: data.date,
    calories: data.calories,
    protein: data.protein,
    insights: data.insights,
    emoji: data.emoji,
    ai_summary: aiSummary,
    email_subject: `📊 Your Daily Nutrition Report - ${data.name} - ${data.date}`
  };

  emailContents.push(emailContent);
}

return emailContents.map(content => ({ json: content }));
